// Flatten dyn/vib/notify velocity (in/s) -> flat topic the MQTT datasource can read.
// dyn/vib/notify nests fields under "Reading"; velocity scalars are VelXrms/VelYrms/VelZrms.
var p = msg.payload;
var r = (p && p.Reading && typeof p.Reading === 'object') ? p.Reading : p;
if (!r || r.Serial === undefined) return null;
function num(v){ return (typeof v === 'number' && isFinite(v)) ? v : null; }
var vx=num(r.VelXrms), vy=num(r.VelYrms), vz=num(r.VelZrms);
var out = { Serial:r.Serial, ID:r.ID,
  vel_x_rms:vx, vel_y_rms:vy, vel_z_rms:vz,
  x_rms:num(r.Xrms), y_rms:num(r.Yrms), z_rms:num(r.Zrms) };
var ax=[vx,vy,vz].filter(function(v){return v!==null;});
if (ax.length){ var s=0; ax.forEach(function(v){s+=v*v;}); out.vel_overall = Math.sqrt(s); }
if (vx===null && vy===null && vz===null) return null; // nothing to publish
msg.payload = out;
msg.topic = 'access360/43250372/derived/vib';
node.status({fill:'green',shape:'dot',text:'vel '+r.Serial});
return msg;
